import{c as a,Q as i,j as n,m as e}from"./chunks/framework.D9IbVcwA.js";const c=JSON.parse('{"title":"005-mini-kernel-entry-3 · 内核入口","description":"","frontmatter":{"title":"005-mini-kernel-entry-3 · 内核入口"},"headers":[],"relativePath":"tutorial/005-mini-kernel-entry-3.md","filePath":"tutorial/005-mini-kernel-entry-3.md","lastUpdated":1779686691000}'),l={name:"tutorial/005-mini-kernel-entry-3.md"};function p(t,s,h,r,d,k){return i(),n("div",null,[...s[0]||(s[0]=[e(`<h1 id="踩过的两个大坑-pdpt-索引幽灵与链接器脚本陷阱" tabindex="-1">踩过的两个大坑：PDPT 索引幽灵与链接器脚本陷阱 <a class="header-anchor" href="#踩过的两个大坑-pdpt-索引幽灵与链接器脚本陷阱" aria-label="Permalink to &quot;踩过的两个大坑：PDPT 索引幽灵与链接器脚本陷阱&quot;">​</a></h1><blockquote><p>标签：PDPT 索引, 页表映射, linker script, LMA, SIZEOF, GDB, VSCode, 远程调试 前置：<a href="./005-mini-kernel-entry-2">005B 从数字到文字的魔法：kprintf</a></p></blockquote><h2 id="写在前面" tabindex="-1">写在前面 <a class="header-anchor" href="#写在前面" aria-label="Permalink to &quot;写在前面&quot;">​</a></h2><p>前两篇我们写了串口驱动和 kprintf 格式化引擎，代码量不大，逻辑也不算复杂。按理说写完之后内核应该能愉快地通过串口输出 <code>Cinux Mini Kernel v0.1.0</code> 了——但如果你跟着 tag 005 的代码一路走来，你一定记得有那么几个时刻，内核启动后串口毫无输出，debugcon 的字符序列突然中断，全局构造函数跳转到了垃圾地址。我血压拉满地调了半天，最后发现新写的代码一点问题都没有，真正的罪魁祸首是两个在更早阶段就埋下的 bug。</p><p>第一个 bug 出在页表映射上：高半核地址 <code>0xFFFFFFFF80000000</code> 的 PDPT 索引被写成了 511，正确的应该是 510——差了那么一个 bit。第二个 bug 出在链接脚本里：用 <code>SIZEOF()</code> 累加计算段的 LMA（Load Memory Address），但 <code>SIZEOF()</code> 不包含段之间的对齐填充，导致 <code>.init_array</code> 里的全局构造函数指针指向了错误的位置，读出来的全是 <code>0xFFFFFFFF</code>。</p><p>这两个 bug 有一个共同特征：identity mapping 下一切正常，只有高半核地址才会触发。这意味着如果你只测了低地址访问就以为&quot;页表没问题&quot;，或者只看了 <code>.text</code> 段就以为&quot;链接脚本没问题&quot;，你可能会被蒙蔽很久。这一篇我们就来拆解这两个幽灵 bug 的侦探过程，顺便把 QEMU + GDB 远程调试和 VSCode 调试配置的实战流程一起讲了。</p><h2 id="环境-背景" tabindex="-1">环境 &amp; 背景 <a class="header-anchor" href="#环境-背景" aria-label="Permalink to &quot;环境 &amp; 背景&quot;">​</a></h2><p>本篇涉及的代码修改不在新写的驱动或库里，而是在之前 tag 就已经存在的文件中：<code>boot/common/long_mode.S</code>（页表设置）和 <code>kernel/mini/linker.ld</code>（链接脚本）。另外还有 <code>boot/stage2.S</code> 中新增的映射验证代码，以及 <code>.vscode/launch.json</code> 和 <code>.vscode/tasks.json</code> 的调试配置。</p><p>调试工具方面，我们用到了 QEMU 的 <code>-s -S</code> 参数启动 GDB stub、命令行 GDB 远程调试、以及 VSCode 的图形化调试界面。三者各有适用场景：debugcon 输出用于快速定位问题区域，GDB 命令行用于精确检查寄存器和内存，VSCode 用于日常的单步调试。</p><h2 id="幽灵-bug-一-pdpt-索引差了一位" tabindex="-1">幽灵 Bug 一：PDPT 索引差了一位 <a class="header-anchor" href="#幽灵-bug-一-pdpt-索引差了一位" aria-label="Permalink to &quot;幽灵 Bug 一：PDPT 索引差了一位&quot;">​</a></h2><h3 id="症状" tabindex="-1">症状 <a class="header-anchor" href="#症状" aria-label="Permalink to &quot;症状&quot;">​</a></h3><p>内核启动后 debugcon 输出停在了 <code>OPL</code>，没有出现后续的字符。<code>OPL</code> 分别代表 Stage2 完成（O）、保护模式进入（P）、Long Mode 进入（L）——说明 bootloader 执行到了 Long Mode 之后就没有然后了。</p><p>但奇怪的是，如果我在 <code>boot.S</code> 里用 identity mapping 地址（0x20000）来测试，内核是能跑的。只有在跳转到高半核地址（0xFFFFFFFF80020000）时才会炸。</p><h3 id="根本原因" tabindex="-1">根本原因 <a class="header-anchor" href="#根本原因" aria-label="Permalink to &quot;根本原因&quot;">​</a></h3><p>问题出在 <code>long_mode.S</code> 的 <code>setup_page_tables</code> 函数中。之前的代码是：</p><div class="language-asm vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">// 错误：PDPT[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">511</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] -&gt; PD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">movl $PD_PHYS_ADDR, %</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">eax</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">orl $0x03, %</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">eax</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">movl %</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">eax</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, PDPT_PHYS_ADDR + (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">511</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> * </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>直觉上&quot;511 看起来更像是最高位&quot;，很多人（包括我）会顺手写 511。但正确答案是 510。让我们重新拆解虚拟地址 <code>0xFFFFFFFF80000000</code> 在四级页表中的索引路径。x86-64 的 4-level paging 把 48 位有效虚拟地址分成四个 9 位的索引，加上 12 位的页偏移。Intel SDM Vol. 3A Chapter 4 对此有完整的描述：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>虚拟地址: 0xFFFFFFFF80000000</span></span>
<span class="line"><span>二进制:   1111...1111 10000000 00000000 00000000 00000000</span></span>
<span class="line"><span></span></span>
<span class="line"><span>PML4 索引 (bits 47:39):  111111111 = 511 = 0x1FF</span></span>
<span class="line"><span>PDPT 索引 (bits 38:30):  100000000 = 510 = 0x1FE   &lt;- 关键！</span></span>
<span class="line"><span>PD   索引 (bits 29:21):  000000000 = 0   = 0x000</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>关键在 PDPT 索引。很多人会以为 <code>0x80000000</code> 的 bit 30 是 1（&quot;毕竟 8 的二进制是 1000&quot;），但实际上 <code>0x80000000</code> 的二进制表示是 <code>10000000 00000000 00000000 00000000</code>——bit 31 是 1，bit 30 是 0。所以 bits 38:30 = <code>111111110</code> = 510，不是 511。</p><p>用 PDPT[511] 的话，CPU 在翻译 <code>0xFFFFFFFF80020000</code> 这个地址时会查找 PDPT[511]，而我们只设了 PDPT[510]，PDPT[511] 是空的（全零，not present），于是触发 Page Fault。这个 bug 的狡猾之处在于 identity mapping 完全正常——用 0x20000 访问内核没问题，只有高半核地址会炸。如果你不主动测试高半核地址，可能很久都不会发现。</p><h3 id="修正" tabindex="-1">修正 <a class="header-anchor" href="#修正" aria-label="Permalink to &quot;修正&quot;">​</a></h3><div class="language-asm vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">// 正确：PDPT[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">510</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] -&gt; PD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">movl $PD_PHYS_ADDR, %</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">eax</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">orl $0x03, %</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">eax</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">movl %</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">eax</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, PDPT_PHYS_ADDR + (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">510</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> * </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)    // 低 </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">32</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 位</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">movl </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">$0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, PDPT_PHYS_ADDR + (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">510</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> * </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) + </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">4</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  // 高 </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">32</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 位清零</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>修正后的代码还多了一条指令：<code>movl $0, offset + 4</code> 把页表项的高 32 位清零。这是因为 x86-64 的页表项是 64 位的，但 <code>setup_page_tables</code> 运行在 32 位保护模式下，<code>movl</code> 只能写 32 位。之前只写了低 32 位，高 32 位依赖 <code>rep stosl</code> 清零后的初始值——这&quot;恰好&quot;是对的（因为物理地址低于 4GB），但不显式清零总让人不踏实。万一后续代码在清零和设置之间写了什么到高 32 位，就会踩坑。显式清零是一种&quot;安全编程&quot;的习惯。</p><h3 id="预防-映射验证代码" tabindex="-1">预防：映射验证代码 <a class="header-anchor" href="#预防-映射验证代码" aria-label="Permalink to &quot;预防：映射验证代码&quot;">​</a></h3><p>为了不再被类似的 bug 偷袭，我们在 <code>stage2.S</code> 跳转到内核之前新增了映射验证：</p><div class="language-asm vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">// </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">Test</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: 验证 identity mapping</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">movq</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $0x20000, %</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">rax</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">movb (%</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">rax</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">), %</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">al</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">             // 读内核第一个字节 (应该是 </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0xFA</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">cli</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">outb %</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">al</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, $DEBUGCON_PORT     // 输出到 debugcon</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">// </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">Test</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: 验证 higher-half mapping</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">movq</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $0xFFFFFFFF80020000, %</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">rax</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">movb (%</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">rax</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">), %</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">al</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">             // 同一个字节通过高半核地址读</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">outb %</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">al</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, $DEBUGCON_PORT     // 应该也是 </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0xFA</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">// </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">Test</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: 跳转信号</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">movb $0x48, %</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">al</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">              // &#39;H&#39; = Higher-half jump</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">outb %</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">al</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, $DEBUGCON_PORT</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><p>Test 1 读 identity mapping 地址，Test 2 读高半核地址——如果页表映射正确，读到的应该是同一个字节。在 <code>debug.log</code> 中你应该看到两个 0xFA 字节（<code>0xFA</code> 是 <code>cli</code> 指令的机器码），然后是 &#39;H&#39;。如果只有一个 0xFA，说明 identity mapping 正常但高半核映射有问题；如果连第一个 0xFA 都没有，说明内核本身没被正确加载。</p><p>这种&quot;在关键步骤前后输出诊断字符&quot;的做法，是裸机开发中最实用的调试手段之一。它不需要任何基础设施——只要 <code>outb</code> 能工作就能用。</p><h2 id="幽灵-bug-二-链接脚本的-lma-计算陷阱" tabindex="-1">幽灵 Bug 二：链接脚本的 LMA 计算陷阱 <a class="header-anchor" href="#幽灵-bug-二-链接脚本的-lma-计算陷阱" aria-label="Permalink to &quot;幽灵 Bug 二：链接脚本的 LMA 计算陷阱&quot;">​</a></h2><h3 id="症状-1" tabindex="-1">症状 <a class="header-anchor" href="#症状-1" aria-label="Permalink to &quot;症状&quot;">​</a></h3><p>页表 bug 修完之后，debugcon 的字符序列变成了 <code>OPL\\xfa\\xfaH\\[1234&#39;</code>——说明 bootloader 跳转成功，内核入口开始执行，设栈（1）、清 BSS（2）都完成了。但在第 3 步（调用全局构造函数）时，内核崩溃了。</p><p>具体的表现是：<code>_init_global_ctors()</code> 遍历 <code>.init_array</code> 段的函数指针数组，但读到的指针值是 <code>0xFFFFFFFF</code>——这显然不是合法的函数地址，CPU 跳转过去直接 Page Fault。</p><h3 id="根本原因-1" tabindex="-1">根本原因 <a class="header-anchor" href="#根本原因-1" aria-label="Permalink to &quot;根本原因&quot;">​</a></h3><p>问题出在链接脚本的 LMA（Load Memory Address）计算上。之前的写法是：</p><div class="language-makefile vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">makefile</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">.text</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> : AT(KERNEL_PHYS_BASE) { ... }</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">.data</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> : AT(KERNEL_PHYS_BASE + SIZEOF(.text)) { ... }</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">.init_array</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> : AT(KERNEL_PHYS_BASE + SIZEOF(.text) + SIZEOF(.data)) { ... }</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>这种累加方式看起来逻辑清晰：<code>.text</code> 从 <code>KERNEL_PHYS_BASE</code> 开始，<code>.data</code> 紧随其后偏移 <code>SIZEOF(.text)</code>，<code>.init_array</code> 再偏移 <code>SIZEOF(.data)</code>。问题在于 <code>SIZEOF()</code> 只返回段内容本身的大小，不包含段之间的对齐填充（alignment padding）。</p><p>举个例子：<code>.text</code> 段可能在 VMA 0xFFFFFFFF80020000 到 0xFFFFFFFF80020FF0，内容大小为 0xFF0 字节。但因为 <code>.data</code> 需要 16 字节对齐，VMA 会跳到 0xFFFFFFFF80021000（多了 0x10 的填充）。此时 <code>SIZEOF(.text)</code> 还是 0xFF0，但 <code>.data</code> 的实际起始偏移应该是 0x1000 而不是 0x0FF0。差了 0x10 字节。</p><p>这种偏移偏差会逐段累积。到 <code>.init_array</code> 的时候，LMA 可能偏差了几十甚至几百字节。bootloader 加载内核映像到物理内存后，<code>.init_array</code> 中的数据实际上不在 <code>ADDR(.init_array) - KERNEL_Virt_BASE</code> 这个物理地址上，而是在偏移了几十个字节的位置。你读到的不是函数指针数组，而是 <code>.data</code> 段中间某个位置的数据——恰好是 <code>0xFFFFFFFF</code>（或者别的垃圾值）。</p><h3 id="修正-1" tabindex="-1">修正 <a class="header-anchor" href="#修正-1" aria-label="Permalink to &quot;修正&quot;">​</a></h3><div class="language-makefile vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">makefile</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">KERNEL_Virt_BASE = 0xFFFFFFFF80000000;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">KERNEL_PHYS_BASE = 0x20000;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SECTIONS {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    . = KERNEL_Virt_BASE + KERNEL_PHYS_BASE;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    .text</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> : AT(ADDR(.text) - KERNEL_Virt_BASE) { ... }</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    .data</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> : AT(ADDR(.data) - KERNEL_Virt_BASE) { ... }</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    .init_array</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> : AT(ADDR(.init_array) - KERNEL_Virt_BASE) { ... }</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    .bss</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> : { ... }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><p>修正后的公式是 <code>AT(ADDR(.section) - KERNEL_Virt_BASE)</code>。<code>ADDR(.section)</code> 返回段的实际 VMA（包含了所有对齐填充后的正确地址），减去 <code>KERNEL_Virt_BASE</code>（0xFFFFFFFF80000000）就得到正确的物理地址。无论中间有多少对齐填充，这个关系始终成立：LMA = VMA - KERNEL_Virt_BASE。</p><p>你可以用 <code>readelf -l build/kernel/mini/mini_kernel</code> 来验证。查看 LOAD 段的 VirtAddr 和 PhysAddr，确保 PhysAddr 是从 0x20000 开始的连续物理地址，而 VirtAddr 是从 0xFFFFFFFF80020000 开始的高半核地址。</p><p>这个 bug 的教训是：在链接脚本中，永远不要用 <code>SIZEOF()</code> 累加来计算 LMA。<code>ADDR() - offset</code> 公式在任何情况下都是正确的，因为它利用了 VMA 和 LMA 之间的固定关系。</p><h2 id="qemu-gdb-远程调试实战" tabindex="-1">QEMU + GDB 远程调试实战 <a class="header-anchor" href="#qemu-gdb-远程调试实战" aria-label="Permalink to &quot;QEMU + GDB 远程调试实战&quot;">​</a></h2><p>找到了 bug 的方向之后，具体的验证过程离不开调试工具。QEMU 内置了 GDB stub 功能，可以通过 <code>-s -S</code> 参数启用。<code>-s</code> 让 QEMU 在 TCP 端口 1234 上监听 GDB 连接，<code>-S</code> 让 CPU 在启动时冻结，等待 GDB 连接后再继续执行。</p><p>Cinux 的 CMake 配置已经把调试模式封装成了 <code>make run-debug</code> 目标。启动流程是这样的：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Terminal 1: 启动 QEMU 调试模式</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run-debug</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># QEMU 启动并暂停，等待 GDB 连接</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Terminal 2: 启动 GDB</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gdb</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build/kernel/mini/mini_kernel</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gdb</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">target</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> remote</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> :1234</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gdb</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">break</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> _start</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gdb</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">continue</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>连接成功后，GDB 会显示 CPU 当前停在的位置（通常是 <code>0x00007c00</code>，即 MBR 入口）。然后你可以在任何地址设断点——比如 <code>break *0xFFFFFFFF80020000</code> 在内核入口设断点，<code>break mini_kernel_main</code> 在 C++ 入口函数设断点。</p><p>调试页表问题时，最常用的命令是查看内存和寄存器：</p><div class="language-plaintext vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">plaintext</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>(gdb) info registers cr3       # 查看 CR3（页表基址）</span></span>
<span class="line"><span>(gdb) x/1gx 0x1000 + 511*8    # 查看 PML4[511]</span></span>
<span class="line"><span>(gdb) x/1gx 0x2000 + 510*8    # 查看 PDPT[510]</span></span>
<span class="line"><span>(gdb) x/1gx 0x2000 + 511*8    # 查看 PDPT[511]（应该是 0）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>调试链接脚本问题时，关键是查看 <code>.init_array</code> 的内容：</p><div class="language-plaintext vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">plaintext</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>(gdb) x/4gx &amp;__init_array_start</span></span>
<span class="line"><span># 如果看到 0xFFFFFFFFFFFFFFFF，说明 LMA 计算有误</span></span>
<span class="line"><span># 如果看到合理的函数地址（如 0xFFFFFFFF80020xxx），说明正确</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>GDB 的 Remote Serial Protocol 本身是一个基于 ASCII hex 的文本协议。GDB 发送 <code>$packet#checksum</code> 格式的数据包，QEMU 返回响应。比如 <code>$g#7a</code> 是读取所有寄存器，<code>$m addr,len#xx</code> 是读取内存。你不需要手动拼这些数据包——GDB 自动处理——但了解底层协议有助于理解调试过程中偶尔出现的超时或连接错误。</p><p>QEMU 文档（<a href="https://www.qemu.org/docs/master/system/gdb.html%EF%BC%89%E5%92%8C" target="_blank" rel="noreferrer">https://www.qemu.org/docs/master/system/gdb.html）和</a> OSDev Wiki 的 GDB 页面（<a href="https://wiki.osdev.org/GDB%EF%BC%89%E6%9C%89%E6%9B%B4%E8%AF%A6%E7%BB%86%E7%9A%84%E8%AF%B4%E6%98%8E%E3%80%82" target="_blank" rel="noreferrer">https://wiki.osdev.org/GDB）有更详细的说明。</a></p><h2 id="vscode-调试配置" tabindex="-1">VSCode 调试配置 <a class="header-anchor" href="#vscode-调试配置" aria-label="Permalink to &quot;VSCode 调试配置&quot;">​</a></h2><p>对于日常开发，每次都要开两个终端、手动输 GDB 命令还是挺烦的。VSCode 的 C++ 调试扩展可以图形化地完成同样的工作。配置文件在 <code>.vscode/launch.json</code>：</p><div class="language-json vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;name&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;QEMU 调试 (mini kernel)&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;type&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;cppdbg&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;request&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;launch&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;program&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;\${workspaceFolder}/build/kernel/mini/mini_kernel&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;MIMode&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;gdb&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;miDebuggerServerAddress&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;localhost:1234&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;setupCommands&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;text&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;-gdb-set architecture i386:x86-64&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;text&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;-gdb-set disassembly-flavor intel&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;text&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;-gdb-set pagination off&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><p>关键配置项是 <code>miDebuggerServerAddress: localhost:1234</code>——告诉 VSCode 的 GDB 前端连接到 QEMU 的 GDB stub。<code>setupCommands</code> 中的 <code>-gdb-set architecture i386:x86-64</code> 是 GDB 17.x 的兼容性修复——新版本的 GDB 在连接 QEMU 时如果不显式设置架构，可能会用错误的反汇编模式。<code>-gdb-set disassembly-flavor intel</code> 把反汇编语法从默认的 AT&amp;T 切换到 Intel 格式——对我们来说其实无所谓（Cinux 的汇编代码都是 AT&amp;T 语法），但有些人可能更习惯 Intel 格式。</p><p>使用流程是：先在一个终端里启动 QEMU 调试模式（<code>cd build &amp;&amp; make run-debug</code>），然后在 VSCode 里按 F5 启动调试。VSCode 会连接到已经运行的 QEMU 实例，加载符号文件，然后在当前 CPU 停止的位置暂停。之后你就可以用 F10 单步跳过、F11 单步进入、Shift+F11 跳出函数——和在用户态程序上调试的体验基本一样。</p><p>VSCode 的 <code>.vscode/tasks.json</code> 还提供了一个 <code>QEMU: Run debug mode</code> 任务，可以用 Ctrl+Shift+B 构建然后在后台启动 QEMU 调试模式。这样你就不需要手动开终端了——按一下快捷键构建和启动，然后 F5 连接。</p><h2 id="调试决策树-从-debugcon-到-gdb" tabindex="-1">调试决策树：从 debugcon 到 GDB <a class="header-anchor" href="#调试决策树-从-debugcon-到-gdb" aria-label="Permalink to &quot;调试决策树：从 debugcon 到 GDB&quot;">​</a></h2><p>经过这两个 bug 的折腾，我总结了一套调试策略的决策树，适用于内核开发的各个阶段：</p><p>第一步永远是看 debugcon 输出。<code>debug.log</code> 里的字符序列告诉你 bootloader 执行到了哪一步。如果序列中断在 <code>OPL</code>，问题在页表跳转；中断在 <code>OPL\\xfa\\xfaH</code> 之后，问题在内核初始化阶段。</p><p>第二步是看串口输出。如果内核能执行到 <code>mini_kernel_main</code>，那 kprintf 应该能工作了。如果串口有输出但内容不对，问题在格式化逻辑或者数据传递。</p><p>第三步才是上 GDB。如果前两步都定位不了问题，就需要在可疑位置设断点，单步执行，检查寄存器和内存。GDB 调试的开销最大（每步暂停 CPU），但也是最精确的工具。</p><p>在 Cinux 的开发实践中，这三步的适用频率大约是 7:2:1——大部分问题通过 debugcon 字符就能定位，少部分需要串口输出验证，真正需要 GDB 的只有最棘手的 bug。</p><h2 id="收尾" tabindex="-1">收尾 <a class="header-anchor" href="#收尾" aria-label="Permalink to &quot;收尾&quot;">​</a></h2><p>回头看这两个 bug，它们的根因都不是什么高深的技术问题——一个是 bit 30 的计算失误，一个是 <code>SIZEOF()</code> vs <code>ADDR()</code> 的区别。但它们的影响范围都很大：PDPT 索引错误导致整个高半核地址空间不可访问，LMA 计算错误导致所有全局对象的构造函数指针变成垃圾值。这两个 bug 的共同特征是&quot;identity mapping 下一切正常&quot;——这恰恰是最危险的地方，因为你可能只测了低地址就以为没问题了。</p><p>调试工具方面，debugcon 字符输出是最轻量的诊断手段，GDB 远程调试是最精确的定位工具，VSCode 把 GDB 包装成了更友好的图形界面。三者配合使用，基本上可以覆盖内核开发中遇到的绝大多数调试场景。</p><p>下一篇我们进入一个完全不同的话题：怎么给内核搭一套测试框架，让它能自动验证自己的行为是否正确——不用每次手动重启 QEMU 然后人眼检查输出。</p><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li><p>Intel 64 and IA-32 Architectures Software Developer&#39;s Manual, Vol. 3A, Section 4.3 — 4-Level Paging：4 级页表结构（PML4 -&gt; PDPT -&gt; PD -&gt; PT），虚拟地址分解（bits 47:39 为 PML4 索引，bits 38:30 为 PDPT 索引，bits 29:21 为 PD 索引），2MB 大页的 PS bit 设置。Cinux 的高半核映射利用 PD[0]~PD[3] 的 2MB 大页条目被 PML4[511]/PDPT[510] 复用。<code>0xFFFFFFFF80000000</code> 的 PDPT 索引计算：bits 38:30 = <code>0b111111110</code> = 0x1FE = 510（bit 30 = 0）。 <a href="https://www.intel.com/content/www/us/en/developer/articles/technical/intel-sdm.html" target="_blank" rel="noreferrer">https://www.intel.com/content/www/us/en/developer/articles/technical/intel-sdm.html</a></p></li><li><p>GNU LD Manual — <code>ADDR(section)</code> and <code>SIZEOF(section)</code>：<code>ADDR()</code> 返回段的 VMA（包含对齐后的正确地址），<code>SIZEOF()</code> 返回段内容大小（不含对齐填充）。Cinux 的链接脚本修正从 <code>SIZEOF()</code> 累加改为 <code>ADDR() - offset</code> 公式。 <a href="https://sourceware.org/binutils/docs/ld/Builtin-Functions.html" target="_blank" rel="noreferrer">https://sourceware.org/binutils/docs/ld/Builtin-Functions.html</a></p></li><li><p>QEMU Documentation — GDB Usage (<a href="https://www.qemu.org/docs/master/system/gdb.html" target="_blank" rel="noreferrer">https://www.qemu.org/docs/master/system/gdb.html</a>)：QEMU 内置 GDB stub 的使用文档，<code>-s</code> 和 <code>-S</code> 参数说明，远程调试协议概述。</p></li><li><p>OSDev Wiki — GDB (<a href="https://wiki.osdev.org/GDB" target="_blank" rel="noreferrer">https://wiki.osdev.org/GDB</a>)：OS 开发环境下的 GDB 远程调试指南，包括 QEMU 集成和常见问题排查。</p></li><li><p>Building a VS Code Debugging Workflow for a Custom x64 OS (<a href="https://www.sqlpassion.at/archive/2025/07/22/building-a-vs-code-debugging-workflow-for-a-custom-x64-operating-system-with-qemu-and-gdb/" target="_blank" rel="noreferrer">https://www.sqlpassion.at/archive/2025/07/22/building-a-vs-code-debugging-workflow-for-a-custom-x64-operating-system-with-qemu-and-gdb/</a>)：VSCode + QEMU + GDB 调试配置的实战经验。</p></li></ul>`,72)])])}const E=a(l,[["render",p]]);export{c as __pageData,E as default};
